-- Generated by infa2dbt
{{ config(materialized='view') }}

WITH staged AS (
    SELECT * FROM {{ ref('stg_citibank_vca') }}
),

validated AS (
    SELECT
        ACTION_TYPE,
        RECORD_ID,
        ISSUER_ID,
        ICA_NBR,
        BANK_NBR,
        USER_NAME,
        REQUEST_ID,
        TRY_TO_NUMBER(MIN_PURCHASE_AMT, 18, 2) AS MIN_PURCHASE_AMT,
        TRY_TO_NUMBER(MAX_PURCHASE_AMT, 18, 2) AS MAX_PURCHASE_AMT,
        UPPER(TRIM(PURCHASE_CURRENCY)) AS PURCHASE_CURRENCY,
        PURCHASE_TYPE,
        V_CARD_ALIAS,
        TRIM(SUPPLIER_NAME) AS SUPPLIER_NAME,
        LOWER(TRIM(SUPPLIER_EMAIL)) AS SUPPLIER_EMAIL,
        MULTI_USE,
        VALID_FROM,
        VALID_TO,
        VALID_FOR,
        CDF_PAYMENT_NUMBER,
        CDF_PAYEE_NUMBER,
        TRY_TO_NUMBER(CDF_PAYMENT_AMOUNT, 18, 2) AS CDF_PAYMENT_AMOUNT,
        CDF_PAYMENT_DATE,
        CDF_PAYEE_NAME,
        FILE_NAME,

        -- Data quality flags
        CASE
            WHEN ACTION_TYPE IN ('A', 'U', 'D') THEN TRUE
            ELSE FALSE
        END AS IS_VALID_ACTION,

        CASE
            WHEN TRY_TO_NUMBER(MIN_PURCHASE_AMT, 18, 2) IS NOT NULL
             AND TRY_TO_NUMBER(MAX_PURCHASE_AMT, 18, 2) IS NOT NULL
             AND TRY_TO_NUMBER(MIN_PURCHASE_AMT, 18, 2) <= TRY_TO_NUMBER(MAX_PURCHASE_AMT, 18, 2)
            THEN TRUE
            ELSE FALSE
        END AS IS_VALID_AMOUNT_RANGE,

        CASE
            WHEN PURCHASE_CURRENCY IN ('USD', 'EUR', 'GBP', 'CAD', 'AUD', 'JPY', 'CHF') THEN TRUE
            ELSE FALSE
        END AS IS_VALID_CURRENCY

    FROM staged
)

SELECT
    *,
    CASE
        WHEN IS_VALID_ACTION AND IS_VALID_AMOUNT_RANGE AND IS_VALID_CURRENCY THEN 'VALID'
        ELSE 'REVIEW'
    END AS VALIDATION_STATUS
FROM validated
